+    if is_disable {
+        return match unsafe { raw_syscall::sys_sigaltstack(ss as *const u8, old_ss as *mut u8) } {
+            Ok(()) => 0,
+            Err(e) => {
+                unsafe { set_abi_errno(e) };
+                -1
+            }
+        };
+    }
